mapper.select:
/* SQL ID : ExamDAO.profQuizListPaging 설 명 : 교수퀴즈목록페이징 */ SELECT * FROM ( SELECT ROW_NUMBER() OVER(ORDER BY QUIZ.EXAM_PSBL_SDTTM DESC, QUIZ.REG_DTTM ASC) AS LINE_NO , QUIZ.* , COUNT(QUIZ.EXAM_BSC_ID) OVER() AS TOTAL_CNT FROM ( WITH SBJCT_USER AS ( SELECT ATNDLC.USER_ID FROM TB_LMS_ATNDLC ATNDLC JOIN TB_LMS_SBJCT SBJCT ON ATNDLC.SBJCT_ID = SBJCT.SBJCT_ID WHERE ATNDLC.AUDITYN = 'N' AND SBJCT.SBJCT_ID = #{sbjctId} ) SELECT EXAM_BSC.EXAM_BSC_ID , EXAM_DTL.EXAM_DTL_ID , EXAM_BSC.EXAM_GBNCD , (SELECT CDNM FROM TB_LMS_CMMN_CD WHERE UP_CD = 'EXAM_GBNCD' AND CD = EXAM_BSC.EXAM_GBNCD) AS EXAM_GBNNM , EXAM_BSC.EXAM_TTL , EXAM_DTL.EXAM_MNTS , EXAM_DTL.EXAM_PSBL_SDTTM , EXAM_DTL.EXAM_PSBL_EDTTM , MRK_RFLTYN , MRK_RFLTRT , (SELECT COUNT(TKEXAM_ID) FROM TB_LMS_TKEXAM WHERE EXAM_DTL_ID = EXAM_DTL.EXAM_DTL_ID AND TKEXAM_CMPTNYN = 'Y' AND DELYN = 'N' AND USER_ID IN (SELECT USER_ID FROM SBJCT_USER)) AS EXAM_EXAMNEE_CNT , (SELECT COUNT(TKEXAM.TKEXAM_ID) FROM TB_LMS_TKEXAM TKEXAM JOIN TB_LMS_TKEXAM_RSLT TKEXAM_RSLT ON TKEXAM.TKEXAM_ID = TKEXAM_RSLT.TKEXAM_ID WHERE TKEXAM.EXAM_DTL_ID = EXAM_DTL.EXAM_DTL_ID AND TKEXAM.DELYN = 'N' AND TKEXAM.USER_ID IN (SELECT USER_ID FROM SBJCT_USER) AND TKEXAM_RSLT.EVLYN = 'Y') AS EXAM_EVLTEE_CNT
, NVL(CASE EXAM_BSC.EXAM_GBNCD WHEN 'QUIZ' THEN (SELECT COUNT(USER_ID) FROM SBJCT_USER) WHEN 'QUIZ_TEAM' THEN (SELECT COUNT(TEAM_MBR.USER_ID) FROM TB_LMS_TEAM_MBR TEAM_MBR JOIN TB_LMS_EXAM_TRGTR EXAM_TRGTR ON TEAM_MBR.TEAM_ID = EXAM_TRGTR.TEAM_ID WHERE EXAM_TRGTR.EXAM_DTL_ID IN (SELECT EXAM_DTL_ID FROM TB_LMS_EXAM_DTL WHERE EXAM_BSC_ID = EXAM_BSC.EXAM_BSC_ID AND USEYN = 'Y' AND DELYN = 'N') AND TEAM_MBR.USER_ID IN (SELECT USER_ID FROM SBJCT_USER) ) WHEN 'QUIZ_EXAM_MID' || 'QUIZ_EXAM_LST' THEN (SELECT COUNT(USER_ID) FROM SBJCT_USER) - (SELECT COUNT(USER_ID) FROM TB_LMS_EXAM_ABSNCE WHERE APLY_STSCD = 'APRV' AND EXAM_BSC_ID = EXAM_BSC.EXAM_BSC_ID AND USER_ID IN (SELECT USER_ID FROM SBJCT_USER)) WHEN 'QUIZ_SBST_EXAM_MID' || 'QUIZ_SBST_EXAM_LST' THEN (SELECT COUNT(USER_ID) FROM TB_LMS_EXAM_ABSNCE WHERE APLY_STSCD = 'APRV' AND EXAM_BSC_ID = EXAM_BSC.EXAM_BSC_ID AND USER_ID IN (SELECT USER_ID FROM SBJCT_USER)) END, 0) AS EXAM_TRGTR_CNT , EXAM_BSC.EXAM_QSTNS_CMPTNYN , EXAM_BSC.MRK_OYN , (SELECT COUNT(QSTN_ID) FROM TB_LMS_QSTN WHERE EXAM_DTL_ID = EXAM_DTL.EXAM_DTL_ID AND QSTN_CNDDT_SEQNO = 1 AND DELYN = 'N') AS QSTN_CNT , EXAM_DTL.REEXAMYN , EXAM_DTL.REEXAM_PSBL_SDTTM , EXAM_DTL.REEXAM_PSBL_EDTTM , CASE WHEN SYSDATE < TO_DATE(EXAM_PSBL_SDTTM, 'YYYYMMDDHH24MISS') THEN 'PRE_EXAM' WHEN SYSDATE BETWEEN TO_DATE(EXAM_PSBL_SDTTM, 'YYYYMMDDHH24MISS') AND TO_DATE(EXAM_PSBL_EDTTM, 'YYYYMMDDHH24MISS') THEN 'IN_PROGRESS' WHEN SYSDATE > TO_DATE(EXAM_PSBL_EDTTM, 'YYYYMMDDHH24MISS') THEN 'DONE' ELSE 'ERROR' END AS EXAM_PRGRS_STS , EXAM_BSC.REG_DTTM FROM TB_LMS_EXAM_BSC EXAM_BSC JOIN ( SELECT DTL.* , ROW_NUMBER() OVER(PARTITION BY EXAM_BSC_ID ORDER BY EXAM_DTL_ID) AS RNUM FROM TB_LMS_EXAM_DTL DTL WHERE DELYN = 'N' AND USEYN = 'Y' ) EXAM_DTL ON EXAM_BSC.EXAM_BSC_ID = EXAM_DTL.EXAM_BSC_ID AND EXAM_DTL.RNUM = 1 JOIN TB_LMS_SBJCT SBJCT ON EXAM_BSC.SBJCT_ID = SBJCT.SBJCT_ID LEFT JOIN TB_LMS_SMSTR_CHRT SMSTR_CHRT ON (SBJCT.SMSTR_CHRT_ID = SMSTR_CHRT.SMSTR_CHRT_ID AND SBJCT.SBJCT_REF_TYCD = 'CHRT') WHERE EXAM_BSC.EXAM_TYCD = 'QUIZ' AND SBJCT.SBJCT_ID = #{sbjctId} AND EXAM_BSC.DELYN = 'N' AND EXAM_BSC.USEYN = 'Y'
AND LOWER(EXAM_BSC.EXAM_TTL) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
) QUIZ ORDER BY QUIZ.EXAM_PSBL_SDTTM ASC, QUIZ.REG_DTTM DESC ) A WHERE 1=1
AND LINE_NO BETWEEN #{firstIndex} +1 AND #{firstIndex} + #{listScale}

		/*
             SQL ID : ExamMapper.quizDtlSelect
             설  명  : 퀴즈상세조회
         */
         SELECT
         	  EXAM_DTL.*
		  FROM TB_LMS_EXAM_DTL EXAM_DTL
		 WHERE EXAM_BSC_ID = #{examBscId}


		 	   AND EXAM_DTL_ID = #{examDtlId}


			   AND ROWNUM = 1

