	WHERE EXAM_BSC_ID = #{examBscId}

	/*
         SQL ID : ExamMapper.examDtlModify
         설  명  : 시험상세수정
     */
	UPDATE TB_LMS_EXAM_DTL SET
		  MDFR_ID   = #{mdfrId}
