mapper.select:
/* SQL ID : ExamDAO.profAuthrtSbjctQuizList 설 명 : 교수권한과목퀴즈목록조회 */ SELECT * FROM ( SELECT ROW_NUMBER() OVER(ORDER BY EXAM_BSC.EXAM_BSC_ID DESC) AS LINE_NO , EXAM_BSC.EXAM_BSC_ID , EXAM_BSC.EXAM_TTL , SBJCT.SBJCT_ID , SBJCT.SBJCTNM , SBJCT.DVCLAS_NO , (SELECT CDNM FROM TB_LMS_CMMN_CD WHERE UP_CD = 'EXAM_GBNCD' AND CD = EXAM_BSC.EXAM_GBNCD) AS EXAM_GBNNM , COUNT(1) OVER() AS TOTAL_CNT FROM TB_LMS_SBJCT_ADM SBJCT_ADM JOIN TB_LMS_EXAM_BSC EXAM_BSC ON SBJCT_ADM.SBJCT_ID = EXAM_BSC.SBJCT_ID AND EXAM_BSC.DELYN = 'N' AND EXAM_BSC.USEYN = 'Y' JOIN TB_LMS_SBJCT SBJCT ON SBJCT.SBJCT_ID = EXAM_BSC.SBJCT_ID LEFT JOIN TB_LMS_CRS_MSTR CRS_MSTR ON (SBJCT.CRS_MSTR_ID = CRS_MSTR.CRS_MSTR_ID AND SBJCT.SBJCT_REF_TYCD = 'CRS') LEFT JOIN TB_LMS_SMSTR_CHRT SMSTR_CHRT ON (SBJCT.SMSTR_CHRT_ID = SMSTR_CHRT.SMSTR_CHRT_ID AND SBJCT.SBJCT_REF_TYCD = 'CHRT') WHERE SBJCT_ADM.USER_ID = #{userId} AND EXAM_BSC.EXAM_GBNCD IN ('QUIZ', 'QUIZ_TEAM') AND EXAM_BSC.EXAM_TYCD = 'QUIZ' AND SBJCT_ADM.SBJCT_ADM_TYCD = 'PROF'
AND SBJCT.SBJCT_YR = #{dgrsYr}
AND SBJCT.SBJCT_SMSTR = #{dgrsSmstrChrt}
AND SBJCT.SBJCT_ID = #{sbjctId}
AND LOWER(EXAM_BSC.EXAM_TTL) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
ORDER BY EXAM_BSC.EXAM_BSC_ID ) A WHERE 1=1
AND LINE_NO BETWEEN #{firstIndex} +1 AND #{firstIndex} + #{listScale}

/* SQL ID : ExamDAO.quizLrnGrpSubAsmtList 설 명 : 퀴즈학습그룹부과제목록조회 */ SELECT TEAM.TEAM_ID , TEAM.TEAMNM , NVL((SELECT USR.USERNM FROM TB_LMS_USER USR JOIN TB_LMS_TEAM_MBR TEAM_MBR ON USR.USER_ID = TEAM_MBR.USER_ID WHERE TEAM_MBR.LDRYN = 'Y' AND TEAM_MBR.TEAM_ID = TEAM.TEAM_ID), '-') AS leaderNm , (SELECT COUNT(tlts.USER_ID) FROM TB_LMS_TEAM_MBR tlts WHERE tlts.TEAM_ID = TEAM.TEAM_ID) AS teamMbrCnt , EXAM_DTL.EXAM_TTL , EXAM_DTL.EXAM_CTS FROM TB_LMS_TEAM TEAM LEFT JOIN TB_LMS_EXAM_TRGTR EXAM_TRGTR ON TEAM.TEAM_ID = EXAM_TRGTR.TEAM_ID AND EXAM_TRGTR.EXAM_DTL_ID IN (SELECT EXAM_DTL_ID FROM TB_LMS_EXAM_BSC WHERE EXAM_BSC_ID = #{examBscId}) LEFT JOIN TB_LMS_EXAM_DTL EXAM_DTL ON EXAM_TRGTR.EXAM_DTL_ID = EXAM_DTL.EXAM_DTL_ID AND EXAM_DTL.DELYN = 'N' AND EXAM_DTL.USEYN = 'Y' AND EXAM_DTL.EXAM_BSC_ID = #{examBscId} WHERE TEAM.LRN_GRP_ID = #{lrnGrpId}
AND EXAM_DTL.EXAM_BSC_ID = #{examBscId}
ORDER BY TEAM.TEAM_ID ASC

mapper.update:
		/*
             SQL ID : ExamDAO.quizMrkRfltrtListModify
             	설  명 : 퀴즈성적반영비율목록수정
         */

         UPDATE TB_LMS_EXAM_BSC SET
         	  MDFR_ID = #{item.mdfrId}
         	, MOD_DTTM = FN_DTTM()
         	, MRK_RFLTRT = #{item.mrkRfltrt}
          WHERE EXAM_BSC_ID = #{item.examBscId}

		/*
             SQL ID : ExamDAO.quizRetkexamListModify
             	설  명 : 퀴즈재응시목록수정
         */

         UPDATE TB_LMS_EXAM_DTL SET
         	  MDFR_ID = #{item.mdfrId}
         	, MOD_DTTM = FN_DTTM()
         	, REEXAMYN = #{item.reexamyn}
         	, REEXAM_PSBL_SDTTM = #{item.reexamPsblSdttm}
         	, REEXAM_PSBL_EDTTM = #{item.reexamPsblEdttm}
         	, REEXAM_MRK_RFLTRT = #{item.reexamMrkRfltrt}
          WHERE EXAM_DTL_ID = #{item.examDtlId}

mapper.select:
/* SQL ID : ExamDAO.listPaging 설 명 : 시험 목록 페이징 */
SELECT ROW_NUMBER() OVER(ORDER BY A.EXAM_SDTTM DESC, A.FRST_INQ_DTTM DESC) AS lineNo , A.* FROM (
) A

/* SQL ID : ExamDAO.listMyCreCrsExam 설 명 : 내 강의에 등록된 시험 리스트 조회 */
SELECT ROW_NUMBER() OVER(ORDER BY C.EXAM_ID DESC) AS LINE_NO , C.EXAM_ID , C.EXAM_TTL , D.SBJCT_ID , D.CRS_ID , D.SBJCTNM , D.DVCLAS_NO , F.SMSTRNM , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = C.ORG_ID AND CTGRCD = 'EXAM_STARE_UNI_CD' AND CD = C.TKEXAM_TYCD) AS EXAM_STARE_TYPE_NM , COUNT(1) OVER() AS TOTAL_CNT FROM SBJCT_PROF A JOIN TB_LMS_EXAM_CRE_CRS_RLTN B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' JOIN TB_LMS_EXAM_BSC C ON C.EXAM_ID = B.EXAM_ID AND C.ORG_ID = #{orgId} AND C.DELYN = 'N' JOIN TB_LMS_SBJCT D ON D.SBJCT_ID = A.SBJCT_ID LEFT JOIN TB_LMS_TERM_CRE_CRS_RLTN E ON E.SBJCT_ID = D.SBJCT_ID LEFT JOIN CRS_SMSTR F ON F.CRS_SMSTR_ID = E.CRS_SMSTR_ID WHERE A.USER_ID = #{rgtrId}
AND C.EXAM_CTGRCD = #{examCtgrCd}
AND F.CRS_SMSTR_ID = #{termCd}
AND D.SBJCT_ID = #{creYear}
AND D.CRS_ID = #{creTerm}
AND D.SBJCT_ID = #{crsCreCd}
AND LOWER(C.EXAM_TTL) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
AND C.TKEXAM_TYCD IN ('M', 'L')
AND C.TKEXAM_TYCD = 'A'
ORDER BY C.EXAM_ID

