/* SQL ID : ExamMapper.copyQuiz 설 명 : 퀴즈 복사 */ INSERT INTO TB_LMS_EXAM_BSC ( EXAM_ID , EXAM_CTGRCD , ORG_ID , EXAM_TTL , EXAM_CTS , EXAM_TYCD , TKEXAM_TYCD , EXAM_SBST_REF_ID , EXAM_ALLOC_TYCD , EXAM_EXPSR_TYCD , QSTN_DSPLY_TYCD , QSTNS_TYCD , TKEXAM_MNTS , QSTN_RNDMYN , MRK_RFLTYN , USEYN , EXAM_QSTNS_CMPTNYN , TMLMTYN , EXAMPPR_OYN , DVCLAS_REGYN , PUSH_NOTIYN , AVG_MRK_OYN , TKEXAM_MNTS_USEYN , MAX_TKEXAM_CNT , STARE_CRIT_PRGR_RATIO , MRK_RFLTRT , EXAM_SDTTM , EXAM_EDTTM , REEXAMYN , RE_EXAM_START_DTTM , RE_EXAM_END_DTTM , REEXAM_RFLTRT , RE_EXAM_STARE_TM , PASS_SCORE , DSBLYN , CNSDR_ADD_MNTS , MRK_OYN , MRK_OPEN_SDTTM , SEC_CERT_CD , DSBL_ADD_TM , DELYN
, REG_YN , RGTR_ID , FRST_INQ_DTTM , MDFR_ID , MOD_DTTM ) SELECT #{examCd} , EXAM_CTGRCD , ORG_ID , EXAM_TTL , EXAM_CTS , EXAM_TYCD , TKEXAM_TYCD , EXAM_SBST_REF_ID , EXAM_ALLOC_TYCD , EXAM_EXPSR_TYCD , QSTN_DSPLY_TYCD , QSTNS_TYCD , TKEXAM_MNTS , QSTN_RNDMYN , MRK_RFLTYN , USEYN , 'N' AS EXAM_QSTNS_CMPTNYN , TMLMTYN , EXAMPPR_OYN , 'N' AS DVCLAS_REGYN , PUSH_NOTIYN , AVG_MRK_OYN , TKEXAM_MNTS_USEYN , MAX_TKEXAM_CNT , STARE_CRIT_PRGR_RATIO , MRK_RFLTRT , EXAM_SDTTM , EXAM_EDTTM , REEXAMYN , RE_EXAM_START_DTTM , RE_EXAM_END_DTTM , REEXAM_RFLTRT , RE_EXAM_STARE_TM , PASS_SCORE , DSBLYN , CNSDR_ADD_MNTS , MRK_OYN , MRK_OPEN_SDTTM , SEC_CERT_CD , DSBL_ADD_TM , DELYN
, REG_YN , #{rgtrId}
, TO_CHAR(SYSDATE + NUMTODSINTERVAL(#{lineNo}, 'SECOND'), 'YYYYMMDDHH24MISS')
, FN_DTTM()
, #{rgtrId}
, TO_CHAR(SYSDATE + NUMTODSINTERVAL(#{lineNo}, 'SECOND'), 'YYYYMMDDHH24MISS')
, FN_DTTM()
FROM TB_LMS_EXAM_BSC WHERE EXAM_ID = #{copyExamCd}

