		/*
             SQL ID : ExamDAO.resetInsRef
             	설  명 : 대체 과제 코드 삭제
        */
        UPDATE TB_LMS_EXAM_BSC SET
        	  EXAM_SBST_REF_ID = NULL
        	, EXAM_SDTTM = NULL
        	, EXAM_EDTTM = NULL

        	, EXAM_TYCD = #{examTypeCd}

         WHERE EXAM_ID = #{examCd}
